const float L1_B1[16] = {-0.048235f, 0.340303f, 0.148967f, -0.420627f, 0.018282f, 0.329203f, -0.148098f, -0.115379f, 0.012040f, 0.175543f, -0.366100f, 0.134599f, 0.279609f, 0.476467f, 0.327031f, -0.367131f};

const float L1_W2[16] = {0.753380f, -0.983825f, -1.068851f, -0.242042f, 0.298075f, 0.464864f, 0.623050f, -0.371319f, -0.768965f, 0.883219f, -0.490647f, -0.230917f, -0.545130f, 0.552644f, 0.428103f, -0.464159f};
const float L1_B2 = -0.376034f;

int model1(const float fv[20]) {
    float x[20];
    for (int i = 0; i < 20; i++)
        x[i] = (fv[i] - L1_SCALER_MEAN[i]) / L1_SCALER_SCALE[i];

    // Hidden layer 0 (20 -> 32) ReLU
    float h0[32];
    for (int j = 0; j < 32; j++) {
        float sum = L1_B0[j];
        for (int i = 0; i < 20; i++)
            sum += x[i] * L1_W0[i][j];
        h0[j] = sum > 0.0f ? sum : 0.0f;
    }

    // Hidden layer 1 (32 -> 16) ReLU
    float h1[16];
    for (int j = 0; j < 16; j++) {
        float sum = L1_B1[j];
        for (int i = 0; i < 32; i++)
            sum += h0[i] * L1_W1[i][j];
        h1[j] = sum > 0.0f ? sum : 0.0f;
    }

    // Output layer (16 -> 1) - binary classification, single neuron
    float score = L1_B2;
    for (int j = 0; j < 16; j++)
        score += h1[j] * L1_W2[j];

    // sigmoid threshold at 0.5 - equivalent to score > 0
    return score > 0.0f ? 1 : 0;  // 0=non-target, 1=target
}
